          "* if user ask about device table use device_scd table and not device\r\n",
          "* when ask about 'ios' or 'android' use deviceType column\r\n",
          "* join with device_scd table is always with 3 column like \" on table_name p\r\n",
          "      left join main.urban.gold_devices_scd d on m.UrbanDeviceId = d.UrbanDeviceId\r\n",
          "      and m.ExternalUserId = d.ExternalUserId\r\n",
          "      and p.etr_ymd between d.from_date\r\n",
          "      and d.to_date\r\n",
          "* when ask about user or customer dont show user='0' or null\r\n",
          "* whaen use column ExternalUserId always use it as string type\r\n",
          "* instead of where DATE use etr_ymd like etr_ymd='2023-01-01'\r\n",
          "* instead of where month use etr_ym like etr_ym='2023-01'\r\n",
          "* instead of where year use etr_y like etr_y='2023'"
        ]
